const cfg = $('Set Config').first().json;
const products = $('Get Products').all().map(i => i.json);
const cats = $('Get Category List').all().map(i => i.json);
const keyCol = cfg.keyColumn || 'Product';
const imgCol = cfg.imageColumn || 'Image URL';
// allowed category/subcategory list for the prompt
const lines = cats.map(c => '- ' + (c['Category']||'') + ' > ' + (c['Subcategory']||'')).filter(s => s.trim() !== '- >');
const listText = lines.join('\n');
function getImg(p){ return p[imgCol] || p['Image URL'] || p['Image'] || p['Image Url'] || p['image'] || ''; }
const out = [];
for (const p of products) {
  const img = getImg(p);
  const cat = (p['Category']==null?'':String(p['Category'])).trim();
  if (!img) continue;        // needs an image
  if (cat) continue;         // already classified -> skip (so re-runs only do new rows)
  const prompt = 'You are a natural stone slab expert. Look at the product image, which is a stone slab/surface.\n'
    + '1) Write ONE short sentence describing the surface feature of the slab (color, veining, finish/texture).\n'
    + '2) Pick the single best Category and Subcategory for this product, using the EXACT names from the allowed list below.\n'
    + 'Return ONLY a JSON object: {"description":"...","category":"...","subcategory":"..."}. No text or markdown outside the JSON.\n\n'
    + 'Allowed Category > Subcategory options:\n' + listText;
  out.push({ json: { key: p[keyCol] || '', imageUrl: img, prompt } });
}
return out;

const aiItems = $input.all();
const src = $('Select & Prompt').all();
const cats = $('Get Category List').all().map(i => i.json);
function norm(s){ return (s==null?'':String(s)).replace(/\s+/g,' ').trim().toLowerCase(); }
function catNum(c){ return c['Number'] || c['Category Number'] || c['Subcategory Number'] || c['ID'] || c['Id'] || ''; }
const out = [];
for (let i=0;i<aiItems.length;i++){
  const r = aiItems[i].json || {};
  let content = r.content || r.text || (r.message && r.message.content) || '';
  if (!content && r.choices && r.choices[0] && r.choices[0].message) content = r.choices[0].message.content || '';
  content = String(content).replace(/```json/gi,'').replace(/```/g,'').trim();
  let ai = {}; try { ai = JSON.parse(content); } catch(e){ ai = {}; }
  const sub = ai.subcategory || '';
  let match = cats.find(c => norm(c['Subcategory']) === norm(sub));
  if (!match && sub) match = cats.find(c => { const s = norm(c['Subcategory']); return s && (s.includes(norm(sub)) || norm(sub).includes(s)); });
  const category = match ? (match['Category']||'') : (ai.category||'');
  const number = match ? String(catNum(match)) : '';
  out.push({ json: {
    'key': src[i].json.key,
    'Product Description': ai.description || '',
    'Category': category,
    'Subcategory': match ? (match['Subcategory']||sub) : sub,
    'Category Number': number
  } });
}
return out;
